INSERT INTO quotes (text, author, category, lang, swipe_dir, pack_name, is_premium) VALUES
  ('You have power over your mind, not outside events. Realize this, and you will find strength.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('The impediment to action advances action. What stands in the way becomes the way.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Waste no more time arguing about what a good man should be. Be one.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('If it is not right, do not do it; if it is not true, do not say it.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Very little is needed to make a happy life; it is all within yourself, in your way of thinking.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Never esteem anything as of advantage to you that will make you break your word or lose your self-respect.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('The happiness of your life depends upon the quality of your thoughts.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Accept the things to which fate binds you, and love the people with whom fate brings you together.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Do not indulge in dreams of what you have not, but count the blessings actually present.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Confine yourself to the present.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('It never ceases to amaze me: we all love ourselves more than other people, but care more about their opinion than our own.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('The best revenge is not to be like your enemy.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Loss is nothing else but change, and change is Nature''s delight.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Nowhere can man find a quieter or more untroubled retreat than in his own soul.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'free', false),
  ('Begin at once to live, and count each separate day as a separate life.', 'Seneca', 'stoicism', 'en', 'up', 'free', false),
  ('It is not that I am brave, it is just that I am busy.', 'Seneca', 'stoicism', 'en', 'up', 'free', false),
  ('Luck is what happens when preparation meets opportunity.', 'Seneca', 'stoicism', 'en', 'up', 'free', false),
  ('We suffer more in imagination than in reality.', 'Seneca', 'stoicism', 'en', 'up', 'free', false),
  ('Retire into yourself as much as possible; associate with those who will make a better man of you.', 'Seneca', 'stoicism', 'en', 'up', 'free', false),
  ('While we are postponing, life speeds by.', 'Seneca', 'stoicism', 'en', 'up', 'free', false),
  ('He who is brave is free.', 'Seneca', 'stoicism', 'en', 'up', 'free', false),
  ('The whole future lies in uncertainty: live immediately.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('No man is free who is not master of himself.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('Make the best use of what is in your power, and take the rest as it happens.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('Seek not the good in external things; seek it in yourself.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('First say to yourself what you would be, and then do what you have to do.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('He is a wise man who does not grieve for the things which he has not, but rejoices for those which he has.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('It''s not what happens to you, but how you react to it that matters.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('Wealth consists not in having great possessions, but in having few wants.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('People are not disturbed by things, but by the view they take of them.', 'Epictetus', 'stoicism', 'en', 'up', 'free', false),
  ('It is the nature of the wise to resist pleasures, but the foolish to be a slave to them.', 'Epictetus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('You become what you give your attention to.', 'Epictetus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The chief task in life is simply this: to identify and separate matters so that I can say clearly to myself which are externals not under my control, and which have to do with the choices I actually control.', 'Epictetus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('If you want to improve, be content to be thought foolish and stupid.', 'Epictetus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The highest good is a mind that despises the accidents of fortune, and rejoices in virtue.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Omnia aliena sunt, tempus tantum nostrum est. All things are alien; time alone is ours.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('True happiness is to enjoy the present, without anxious dependence upon the future.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('He suffers more than necessary, who suffers before it is necessary.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('A gem cannot be polished without friction, nor a man without trials.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('It is not the man who has too little, but the man who craves more, that is poor.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('There is nothing the busy man is less busied with than living; there is nothing harder to learn.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Do not pray for easy lives. Pray to be stronger men.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The bravest sight in the world is to see a great man struggling against adversity.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Every new beginning comes from some other beginning''s end.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('How long are you going to wait before you demand the best for yourself?', 'Epictetus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Examine what you are attached to, what you fear, what you desire, and what you resent.', 'Epictetus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The wise man neither rejects life nor fears death.', 'Epicurus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Of all the things which wisdom provides to make us entirely happy, much the greatest is the possession of friendship.', 'Epicurus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Do not spoil what you have by desiring what you have not.', 'Epicurus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The art of living well and the art of dying well are one.', 'Epicurus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Man conquers the world by conquering himself.', 'Zeno of Citium', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Well-being is attained by little and little, and nevertheless is no little thing itself.', 'Zeno of Citium', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Fate leads the willing and drags along the reluctant.', 'Cleanthes', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Reason is not measured by size or height, but by principle.', 'Epictetus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The good man is happy even if he is poor, exiled, deformed and in chains.', 'Chrysippus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('When you arise in the morning, think of what a precious privilege it is to be alive, to breathe, to think, to enjoy, to love.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Look well into thyself; there is a source of strength which will always spring up if thou wilt always look.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The object of life is not to be on the side of the majority, but to escape finding oneself in the ranks of the insane.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Everything we hear is an opinion, not a fact. Everything we see is a perspective, not the truth.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('It is not death that a man should fear, but he should fear never beginning to live.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The secret of all victory lies in the organization of the non-obvious.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Receive without pride, relinquish without struggle.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('The man who has anticipated the coming of troubles takes away their power when they arrive.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Set aside a certain number of days, during which you shall be content with the scantiest and cheapest fare.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Conduct yourself toward every person as if you might one day have unlimited power over them.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('If you want to live a happy life, tie it to a goal, not to people or things.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Dwell on the beauty of life. Watch the stars, and see yourself running with them.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('How often have I breathed easier for having borne some trouble patiently? It always looked greater before it came.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Let philosophy mold and shape you; let it stand as a test of your actions and purposes.', 'Seneca', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('No one can step in the same river twice, for it is not the same river and one is not the same person.', 'Heraclitus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('Character is destiny.', 'Heraclitus', 'stoicism', 'en', 'up', 'stoicism_pack', true),
  ('To complain of the age we live in, to murmur at the present possessors of power, to lament the past, to conceive extravagant hopes of the future, are the common dispositions of the greatest part of mankind.', 'Marcus Aurelius', 'stoicism', 'en', 'up', 'stoicism_pack', true),
