-- MindScrolling — Core Philosophical Quotes Seed (298 quotes)
-- Generated from data/quotes_core.json  (misattributions corrected)
-- Run in Supabase SQL Editor

BEGIN;

-- Safety: uncomment to wipe existing rows first
-- TRUNCATE quotes RESTART IDENTITY CASCADE;


COMMIT;

-- Verification
SELECT category,
       COUNT(*)                                    AS total,
       COUNT(*) FILTER (WHERE is_premium = false)  AS free_count,
       COUNT(*) FILTER (WHERE is_premium = true)   AS premium_count
FROM quotes
GROUP BY category
ORDER BY category;
